import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,e as t}from"./app-706bfe03.js";const p={},o=t(`<h1 id="组件化" tabindex="-1"><a class="header-anchor" href="#组件化" aria-hidden="true">#</a> 组件化</h1><p>vue 的一个核心思想是组件化。</p><p>组件化就是把⻚面拆分成多个组件，每个组件依赖的 CSS、JavaScript、模板、图片等资源放在一起开发维护。组件是资源独立的，在系统内部可复用，组件可以嵌套。</p><p>举个例子：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> app <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Vue</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">el</span><span class="token operator">:</span> <span class="token string">&#39;#app&#39;</span><span class="token punctuation">,</span>
  <span class="token function-variable function">render</span><span class="token operator">:</span> <span class="token parameter">h</span> <span class="token operator">=&gt;</span> <span class="token function">h</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span> <span class="token comment">// h 是 $createElement 方法</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre></div><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// App.vue</span>
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;app&#39;</span>
<span class="token punctuation">}</span>
</code></pre></div><p>上章介绍过，<code>h =&gt; h(App)</code> 会在 <code>_render</code> 中执行。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/render</span>
<span class="token class-name">Vue</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">_render</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  vnode <span class="token operator">=</span> vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span><span class="token function">render</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>_renderProxy<span class="token punctuation">,</span> vm<span class="token punctuation">.</span>$createElement<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">initRender</span> <span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">vm</span><span class="token operator">:</span> Component</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 编译 template 得到 render 函数时使用</span>
  vm<span class="token punctuation">.</span><span class="token function-variable function">$createElement</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">createElement</span><span class="token punctuation">(</span>vm<span class="token punctuation">,</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d<span class="token punctuation">,</span> <span class="token boolean">true</span><span class="token punctuation">)</span>
  <span class="token comment">// 手写 render 函数时使用</span>
  vm<span class="token punctuation">.</span><span class="token function-variable function">_c</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">createElement</span><span class="token punctuation">(</span>vm<span class="token punctuation">,</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">,</span> d<span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span>

<span class="token comment">// core/vdom/create-element</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">createElement</span> <span class="token punctuation">(</span><span class="token parameter">context<span class="token punctuation">,</span> tag<span class="token punctuation">,</span> <span class="token operator">...</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 对参数做些处理判断 ...</span>
  <span class="token keyword">return</span> <span class="token function">_createElement</span><span class="token punctuation">(</span>context<span class="token punctuation">,</span> tag<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span> <span class="token comment">// context = vm, tag = App</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>$createElement</code> 方法会调用 <code>_createElement</code> 方法。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/create-element.js</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">_createElement</span> <span class="token punctuation">(</span><span class="token parameter">context<span class="token punctuation">,</span> tag<span class="token punctuation">,</span> data<span class="token punctuation">,</span> <span class="token operator">...</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">typeof</span> tag <span class="token operator">===</span> <span class="token string">&#39;string&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    vnode <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">VNode</span><span class="token punctuation">(</span>tag<span class="token punctuation">,</span> data<span class="token punctuation">,</span> children<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// tag = App</span>
    vnode <span class="token operator">=</span> <span class="token function">createComponent</span><span class="token punctuation">(</span>tag<span class="token punctuation">,</span> data<span class="token punctuation">,</span> context<span class="token punctuation">,</span> children<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token keyword">return</span> vnode
<span class="token punctuation">}</span>
</code></pre></div><p>由于 <code>tag = App</code>，即 <code>App.vue</code> 导出的对象，因此这里会走到 <code>createComponent</code>，并将 App 组件对象作为构造器参数传入，即 <code>{ name: &#39;app&#39; }</code>。</p><h2 id="createcomponent-创建组件-vnode" tabindex="-1"><a class="header-anchor" href="#createcomponent-创建组件-vnode" aria-hidden="true">#</a> createComponent 创建组件 VNode</h2><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/create-component</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">createComponent</span> <span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">Ctor</span><span class="token operator">:</span> Component <span class="token operator">|</span> Function <span class="token operator">|</span> Object <span class="token operator">|</span> <span class="token keyword">void</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> baseCtor <span class="token operator">=</span> context<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>_base

  <span class="token comment">// 将组件对象转成构造函数，这里的 Ctor = App</span>
  <span class="token comment">// plain options object: turn it into a constructor</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isObject</span><span class="token punctuation">(</span>Ctor<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    Ctor <span class="token operator">=</span> baseCtor<span class="token punctuation">.</span><span class="token function">extend</span><span class="token punctuation">(</span>Ctor<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token comment">// ...</span>

  <span class="token comment">// 安装组件 hooks</span>
  <span class="token comment">// install component management hooks onto the placeholder node</span>
  <span class="token function">installComponentHooks</span><span class="token punctuation">(</span>data<span class="token punctuation">)</span>
  <span class="token comment">// ...</span>

  <span class="token comment">// 创建 vnode</span>
  <span class="token comment">// return a placeholder vnode</span>
  <span class="token keyword">const</span> name <span class="token operator">=</span> Ctor<span class="token punctuation">.</span>options<span class="token punctuation">.</span>name <span class="token operator">||</span> tag
  <span class="token keyword">const</span> vnode <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">VNode</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">vue-component-</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>Ctor<span class="token punctuation">.</span>cid<span class="token interpolation-punctuation punctuation">}</span></span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>name <span class="token operator">?</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">-</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>name<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span> <span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
  <span class="token keyword">return</span> vnode
<span class="token punctuation">}</span>
</code></pre></div><p><code>createComponent</code> 的三个核心步骤：</p><ul><li>将组件对象转成构造函数</li><li>安装组件 hooks</li><li>创建 vnode</li></ul><p>注意，<code>createComponent</code> 返回的只是组件的占位符 vnode，此时 App 组件还未真正 patch。</p><h3 id="vue-extend-组件继承" tabindex="-1"><a class="header-anchor" href="#vue-extend-组件继承" aria-hidden="true">#</a> Vue.extend()组件继承</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> baseCtor <span class="token operator">=</span> context<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>_base <span class="token comment">// Vue</span>
<span class="token comment">// 将组件对象转成构造函数，这里的 Ctor = App</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isObject</span><span class="token punctuation">(</span>Ctor<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  Ctor <span class="token operator">=</span> baseCtor<span class="token punctuation">.</span><span class="token function">extend</span><span class="token punctuation">(</span>Ctor<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><p>在 <code>initGlobalAPI</code> 函数中，有 <code>Vue.options._base = Vue</code>，所以这段代码相当于：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>Ctor <span class="token operator">=</span> Vue<span class="token punctuation">.</span><span class="token function">extend</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span>
</code></pre></div><p>来看下 <code>Vue.extend</code> 的代码：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/global-api/extend</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">initExtend</span> <span class="token punctuation">(</span><span class="token parameter">Vue</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  Vue<span class="token punctuation">.</span><span class="token function-variable function">extend</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">extendOptions</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> Super <span class="token operator">=</span> <span class="token keyword">this</span>
    <span class="token keyword">const</span> SuperId <span class="token operator">=</span> Super<span class="token punctuation">.</span>cid

    <span class="token comment">// 如果有缓存，则直接返回，避免重复构造</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>cachedCtors<span class="token punctuation">[</span>SuperId<span class="token punctuation">]</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">return</span> cachedCtors<span class="token punctuation">[</span>SuperId<span class="token punctuation">]</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">const</span> <span class="token function-variable function">Sub</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token function">VueComponent</span> <span class="token punctuation">(</span><span class="token parameter">options</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token keyword">this</span><span class="token punctuation">.</span><span class="token function">_init</span><span class="token punctuation">(</span>options<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>

    <span class="token comment">// 继承 Vue</span>
    <span class="token class-name">Sub</span><span class="token punctuation">.</span>prototype <span class="token operator">=</span> Object<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token class-name">Super</span><span class="token punctuation">.</span>prototype<span class="token punctuation">)</span>
    <span class="token class-name">Sub</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span>constructor <span class="token operator">=</span> Sub
    <span class="token comment">// ...</span>
    Sub<span class="token punctuation">[</span><span class="token string">&#39;super&#39;</span><span class="token punctuation">]</span> <span class="token operator">=</span> Super

    <span class="token comment">// 挂载 Vue 的方法</span>
    Sub<span class="token punctuation">.</span>extend <span class="token operator">=</span> Super<span class="token punctuation">.</span>extend
    Sub<span class="token punctuation">.</span>mixin <span class="token operator">=</span> Super<span class="token punctuation">.</span>mixin
    Sub<span class="token punctuation">.</span>use <span class="token operator">=</span> Super<span class="token punctuation">.</span>use

    <span class="token comment">// cache constructor 避免重复构造</span>
    cachedCtors<span class="token punctuation">[</span>SuperId<span class="token punctuation">]</span> <span class="token operator">=</span> Sub

    <span class="token keyword">return</span> Sub
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>Vue.extend</code> 就是返回了一个 sub，它继承于 vue 并挂载了一些 vue 的方法。</p><p>实例化 sub 时，就会执行 <code>_init</code> 方法，这样就再次走到了 vue 实例化的逻辑。</p><h3 id="安装组件-hooks" tabindex="-1"><a class="header-anchor" href="#安装组件-hooks" aria-hidden="true">#</a> 安装组件 hooks</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// install component management hooks onto the placeholder node</span>
<span class="token function">installComponentHooks</span><span class="token punctuation">(</span>data<span class="token punctuation">)</span>
</code></pre></div><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// inline hooks to be invoked on component VNodes during patch</span>
<span class="token keyword">const</span> componentVNodeHooks <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token function">init</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">prepatch</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">insert</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">destroy</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token comment">/* ... */</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
<span class="token keyword">const</span> hooksToMerge <span class="token operator">=</span> Object<span class="token punctuation">.</span><span class="token function">keys</span><span class="token punctuation">(</span>componentVNodeHooks<span class="token punctuation">)</span>
</code></pre></div><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">installComponentHooks</span> <span class="token punctuation">(</span><span class="token parameter">data</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> hooks <span class="token operator">=</span> data<span class="token punctuation">.</span>hook <span class="token operator">||</span> <span class="token punctuation">(</span>data<span class="token punctuation">.</span>hook <span class="token operator">=</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">)</span>

  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">let</span> key <span class="token keyword">of</span> hooksToMerge<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> existing <span class="token operator">=</span> hooks<span class="token punctuation">[</span>key<span class="token punctuation">]</span>
    <span class="token keyword">const</span> toMerge <span class="token operator">=</span> componentVNodeHooks<span class="token punctuation">[</span>key<span class="token punctuation">]</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>existing <span class="token operator">!==</span> toMerge <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span><span class="token punctuation">(</span>existing <span class="token operator">&amp;&amp;</span> existing<span class="token punctuation">.</span>_merged<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      hooks<span class="token punctuation">[</span>key<span class="token punctuation">]</span> <span class="token operator">=</span> existing <span class="token operator">?</span> <span class="token function">mergeHook</span><span class="token punctuation">(</span>toMerge<span class="token punctuation">,</span> existing<span class="token punctuation">)</span> <span class="token operator">:</span> toMerge
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>整个 <code>installComponentHooks</code> 的过程就是把 <code>componentVNodeHooks</code> 的函数合并到 <code>data.hook</code> 中，并在 VNode 的 patch 过程中执行，执行细节后面会介绍。</p><p>在合并过程中，如果某个钩子已经存在，则通过 <code>mergeHook</code> 将两个函数合并。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">mergeHook</span> <span class="token punctuation">(</span><span class="token parameter">f1<span class="token punctuation">,</span> f2</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 用一个新函数将两个钩子函数包裹</span>
  <span class="token keyword">const</span> <span class="token function-variable function">merged</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">a<span class="token punctuation">,</span> b</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token function">f1</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span>
    <span class="token function">f2</span><span class="token punctuation">(</span>a<span class="token punctuation">,</span> b<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  merged<span class="token punctuation">.</span>_merged <span class="token operator">=</span> <span class="token boolean">true</span>
  <span class="token keyword">return</span> merged
<span class="token punctuation">}</span>
</code></pre></div><h3 id="创建-vnode" tabindex="-1"><a class="header-anchor" href="#创建-vnode" aria-hidden="true">#</a> 创建 VNode</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// return a placeholder vnode</span>
<span class="token keyword">const</span> name <span class="token operator">=</span> Ctor<span class="token punctuation">.</span>options<span class="token punctuation">.</span>name <span class="token operator">||</span> tag
<span class="token keyword">const</span> vnode <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">VNode</span><span class="token punctuation">(</span>
  <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">vue-component-</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>Ctor<span class="token punctuation">.</span>cid<span class="token interpolation-punctuation punctuation">}</span></span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>name <span class="token operator">?</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">-</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>name<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span> <span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">,</span><span class="token operator">...</span>
<span class="token punctuation">)</span>

<span class="token keyword">return</span> vnode
</code></pre></div><p>最后一步很简单，就是创建一个 vnode 返回。</p><p>App vnode 的数据结构如下：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token literal-property property">children</span><span class="token operator">:</span> <span class="token keyword">undefined</span>
<span class="token literal-property property">componentInstance</span><span class="token operator">:</span> <span class="token keyword">undefined</span>
<span class="token literal-property property">componentOptions</span><span class="token operator">:</span> <span class="token punctuation">{</span><span class="token literal-property property">propsData</span><span class="token operator">:</span> <span class="token keyword">undefined</span><span class="token punctuation">,</span> <span class="token literal-property property">children</span><span class="token operator">:</span> <span class="token keyword">undefined</span><span class="token punctuation">,</span> <span class="token literal-property property">Ctor</span><span class="token operator">:</span> ƒ<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">}</span>
<span class="token literal-property property">context</span><span class="token operator">:</span> Vue
<span class="token literal-property property">data</span><span class="token operator">:</span> <span class="token punctuation">{</span><span class="token literal-property property">on</span><span class="token operator">:</span> <span class="token keyword">undefined</span><span class="token punctuation">,</span> <span class="token literal-property property">hook</span><span class="token operator">:</span> <span class="token punctuation">{</span>…<span class="token punctuation">}</span><span class="token punctuation">}</span>
<span class="token literal-property property">elm</span><span class="token operator">:</span> <span class="token keyword">undefined</span>
<span class="token literal-property property">isRootInsert</span><span class="token operator">:</span> <span class="token boolean">true</span>
<span class="token literal-property property">key</span><span class="token operator">:</span> <span class="token keyword">undefined</span>
<span class="token literal-property property">parent</span><span class="token operator">:</span> <span class="token keyword">undefined</span>
<span class="token literal-property property">tag</span><span class="token operator">:</span> <span class="token string">&quot;vue-component-1-App&quot;</span>
<span class="token literal-property property">text</span><span class="token operator">:</span> <span class="token keyword">undefined</span>
<span class="token comment">// ...</span>
</code></pre></div><p>需要注意的是组件的 vnode 是没有 children 的，这点很关键，它只是一个占位符。</p><h2 id="patch-组件-vnode" tabindex="-1"><a class="header-anchor" href="#patch-组件-vnode" aria-hidden="true">#</a> patch 组件 VNode</h2><p>App vnode 不包含内部节点的 vnode（没有 children），它只是个占位符，在 patch 后会被替换掉。</p><p><strong>组件的 patch 过程会创建内部节点的 vnode 并创建真正的 dom 节点。</strong></p><p>和普通 vnode 一样，<code>vm._render</code> 之后会调用 <code>vm.update</code>、<code>vm.__patch__</code>，最终调用 <code>createElm</code> 函数创建元素节点。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/patch</span>
<span class="token keyword">function</span> <span class="token function">createElm</span><span class="token punctuation">(</span><span class="token parameter">vnode</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 尝试以组件 vnode 方式创建</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">createComponent</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">,</span> parentElm<span class="token punctuation">,</span> refElm<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span>
  <span class="token punctuation">}</span>
  <span class="token comment">// 普通 vnode 的流程</span>
<span class="token punctuation">}</span>
</code></pre></div><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/patch</span>
<span class="token keyword">function</span> <span class="token function">createComponent</span> <span class="token punctuation">(</span><span class="token parameter">vnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">,</span> parentElm<span class="token punctuation">,</span> refElm</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">let</span> i <span class="token operator">=</span> vnode<span class="token punctuation">.</span>data
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isDef</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
		<span class="token comment">// ...</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isDef</span><span class="token punctuation">(</span>i <span class="token operator">=</span> i<span class="token punctuation">.</span>hook<span class="token punctuation">)</span> <span class="token operator">&amp;&amp;</span> <span class="token function">isDef</span><span class="token punctuation">(</span>i <span class="token operator">=</span> i<span class="token punctuation">.</span>init<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token function">i</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> <span class="token boolean">false</span> <span class="token comment">/* hydrating */</span><span class="token punctuation">)</span> <span class="token comment">// 调用 init 钩子</span>
    <span class="token punctuation">}</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isDef</span><span class="token punctuation">(</span>vnode<span class="token punctuation">.</span>componentInstance<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// init 方法中会赋值 vnode.componentInstance</span>
      <span class="token function">initComponent</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">)</span>
      <span class="token function">insert</span><span class="token punctuation">(</span>parentElm<span class="token punctuation">,</span> vnode<span class="token punctuation">.</span>elm<span class="token punctuation">,</span> refElm<span class="token punctuation">)</span>
      <span class="token comment">// ...</span>
      <span class="token keyword">return</span> <span class="token boolean">true</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p><code>createComponent</code> 先调用 <code>init</code> 钩子函数（上节 <code>installComponentHooks</code> 中挂载）。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vodm/create-component</span>
<span class="token keyword">const</span> componentVNodeHooks <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token function">init</span> <span class="token punctuation">(</span><span class="token parameter">vnode<span class="token punctuation">,</span> hydrating</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> child
  		<span class="token operator">=</span> vnode<span class="token punctuation">.</span>componentInstance <span class="token comment">// 记住这个 vnode.componentInstance</span>
  		<span class="token operator">=</span> <span class="token function">createComponentInstanceForVnode</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> activeInstance<span class="token punctuation">)</span>
    child<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span>hydrating <span class="token operator">?</span> vnode<span class="token punctuation">.</span>elm <span class="token operator">:</span> <span class="token keyword">undefined</span><span class="token punctuation">,</span> hydrating<span class="token punctuation">)</span>
  <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">prepatch</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">insert</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token function">destroy</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span><span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>init 钩子通过 <code>createComponentInstanceForVnode</code> 创建了一个 vue 的实例，然后调用 $mount 挂载子组件。对应例子，就是初始化并挂载 App。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/create-component</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">createComponentInstanceForVnode</span> <span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">const</span> <span class="token literal-property property">options</span><span class="token operator">:</span> InternalComponentOptions <span class="token operator">=</span> <span class="token punctuation">{</span>
    <span class="token literal-property property">_isComponent</span><span class="token operator">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">// _isComponent 会在 _init 时用到</span>
    <span class="token literal-property property">_parentVnode</span><span class="token operator">:</span> vnode<span class="token punctuation">,</span>
    parent
  <span class="token punctuation">}</span>
  <span class="token comment">// check inline-template render functions</span>
  <span class="token keyword">const</span> inlineTemplate <span class="token operator">=</span> vnode<span class="token punctuation">.</span>data<span class="token punctuation">.</span>inlineTemplate
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">isDef</span><span class="token punctuation">(</span>inlineTemplate<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    options<span class="token punctuation">.</span>render <span class="token operator">=</span> inlineTemplate<span class="token punctuation">.</span>render
    options<span class="token punctuation">.</span>staticRenderFns <span class="token operator">=</span> inlineTemplate<span class="token punctuation">.</span>staticRenderFns
  <span class="token punctuation">}</span>

  <span class="token comment">// 相当于 new Sub(options)，这会调用 vm._init 方法</span>
  <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">vnode<span class="token punctuation">.</span>componentOptions<span class="token punctuation">.</span>Ctor</span><span class="token punctuation">(</span>options<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><p>上述代码需要注意的有两点：</p><ul><li><p><code>new vnode.componentOptions.Ctor(options)</code> 相当于 <code>new Sub(options)</code>，即调用 App 的构造器</p></li><li><p><code>_isComponent: true</code> 表示当前初始化的是一个组件， 它会在 <code>_init</code> 函数中用到</p></li></ul><h3 id="init-component" tabindex="-1"><a class="header-anchor" href="#init-component" aria-hidden="true">#</a> _init component</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/init</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">initMixin</span> <span class="token punctuation">(</span><span class="token parameter">Vue</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token class-name">Vue</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">_init</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">options</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>options <span class="token operator">&amp;&amp;</span> options<span class="token punctuation">.</span>_isComponent<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token function">initInternalComponent</span><span class="token punctuation">(</span>vm<span class="token punctuation">,</span> options<span class="token punctuation">)</span> <span class="token comment">// 初始化内部组件（子组件）</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
      vm<span class="token punctuation">.</span>$options <span class="token operator">=</span> <span class="token function">mergeOptions</span><span class="token punctuation">(</span><span class="token operator">...</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span>

   	<span class="token function">initLifecycle</span><span class="token punctuation">(</span>vm<span class="token punctuation">)</span>
    <span class="token function">initEvents</span><span class="token punctuation">(</span>vm<span class="token punctuation">)</span>
    <span class="token function">initRender</span><span class="token punctuation">(</span>vm<span class="token punctuation">)</span>
    <span class="token comment">// ...</span>

    <span class="token keyword">if</span> <span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>el<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      vm<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>el<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>组件的 options 中<code>_isComponent: true</code>，因此走到了 <code>initInternalComponent</code>。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/init</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">initInternalComponent</span><span class="token punctuation">(</span><span class="token parameter">vm<span class="token punctuation">,</span> options</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> opts Object<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>constructor<span class="token punctuation">.</span>options<span class="token punctuation">)</span>

  opts<span class="token punctuation">.</span>parent <span class="token operator">=</span> options<span class="token punctuation">.</span>parent
  opts<span class="token punctuation">.</span>_parentVnode <span class="token operator">=</span> options<span class="token punctuation">.</span>_parentVnode
  <span class="token comment">// 其他一些对 opts 的属性赋值 ...</span>

  <span class="token keyword">if</span> <span class="token punctuation">(</span>options<span class="token punctuation">.</span>render<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    opts<span class="token punctuation">.</span>render <span class="token operator">=</span> options<span class="token punctuation">.</span>render <span class="token comment">// 终于拿到 App 的 render 函数</span>
    opts<span class="token punctuation">.</span>staticRenderFns <span class="token operator">=</span> options<span class="token punctuation">.</span>staticRenderFns
  <span class="token punctuation">}</span>
  vm<span class="token punctuation">.</span>$options <span class="token operator">=</span> opts
<span class="token punctuation">}</span>
</code></pre></div><p>初始化、合并 options 后，就要开始挂载组件了。</p><p>再来看一下<code> _init</code> 函数最后执行的代码：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/init</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>el<span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">// false，组件在初始化时是不传 el 的</span>
  vm<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>el<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><p><strong>组件在初始化时是不传 el 的，组件自己接管了 $mount 的过程。</strong></p><h3 id="mount-component" tabindex="-1"><a class="header-anchor" href="#mount-component" aria-hidden="true">#</a> $mount component</h3><p>回想下组件的 init 钩子函数：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> componentVNodeHooks <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token function">init</span> <span class="token punctuation">(</span><span class="token parameter">vnode<span class="token punctuation">,</span> hydrating</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> child <span class="token operator">=</span> <span class="token function">createComponentInstanceForVnode</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> activeInstance<span class="token punctuation">)</span>
    child<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span>hydrating <span class="token operator">?</span> vnode<span class="token punctuation">.</span>elm <span class="token operator">:</span> <span class="token keyword">undefined</span><span class="token punctuation">,</span> hydrating<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>在执行 <code>createComponentInstanceForVnode</code> 后，执行 <code>child.$mount</code>。</p><p><code>hydrating</code> 在服务端渲染时才为 true。因此这里相当于：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code>child<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span><span class="token keyword">undefined</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>
</code></pre></div><p>上章 “vue 实例的挂载” 中介绍过，$mount 会在 “将 template 模板编译成 render 函数” 等操作，也就是此时，渲染对象从组件 vnode 变成了组件的 render 函数。即 App.vue 中的 template 内容对应的 render 函数。</p><p>得到 render 函数后，调用 <code>mountComponent</code> 方法，进而执行 <code>vm._render</code> 方法渲染。</p><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1gydci7akqpj30df0fkgmi.jpg" alt=""></p><h3 id="render、-update-component" tabindex="-1"><a class="header-anchor" href="#render、-update-component" aria-hidden="true">#</a> _render、_update component</h3><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/render</span>
<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">renderMixin</span><span class="token punctuation">(</span><span class="token parameter">Vue</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token class-name">Vue</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">_render</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> <span class="token punctuation">{</span> render<span class="token punctuation">,</span> _parentVnode <span class="token punctuation">}</span> <span class="token operator">=</span> vm<span class="token punctuation">.</span>$options

    <span class="token comment">// 当前组件的渲染 vnode</span>
    <span class="token keyword">let</span> vnode <span class="token operator">=</span> <span class="token function">render</span><span class="token punctuation">.</span><span class="token function">call</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>_renderProxy<span class="token punctuation">,</span> vm<span class="token punctuation">.</span>$createElement<span class="token punctuation">)</span>
    <span class="token comment">// 当前组件的父 vnode，即 vue-component-1-App</span>
    vnode<span class="token punctuation">.</span>parent <span class="token operator">=</span> vm<span class="token punctuation">.</span>$vnode <span class="token operator">=</span> _parentVnode

    <span class="token keyword">return</span> vnode
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>这段代码需要注意下 vnode 的父子关系：当前组件的<strong>渲染 vnode</strong> 的父亲是 App 的<strong>组件 vnode</strong>，即 <em>vue-component-1-App</em>。</p><p>render 得到 vnode 后，接下来要执行 <code>vm._update</code> 去渲染 vnode 了。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/lifecycle</span>
<span class="token keyword">export</span> <span class="token keyword">let</span> activeInstance <span class="token operator">=</span> <span class="token keyword">null</span>

<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">setActiveInstance</span><span class="token punctuation">(</span><span class="token parameter">vm</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> prevActiveInstance <span class="token operator">=</span> activeInstance
  activeInstance <span class="token operator">=</span> vm
  <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    activeInstance <span class="token operator">=</span> prevActiveInstance
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">lifecycleMixin</span> <span class="token punctuation">(</span><span class="token parameter">Vue</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token class-name">Vue</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">_update</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">vnode<span class="token punctuation">,</span> hydrating</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> vm <span class="token operator">=</span> <span class="token keyword">this</span>
    vm<span class="token punctuation">.</span>_vnode <span class="token operator">=</span> vnode <span class="token comment">// _render 函数返回的组件渲染 vnode</span>
    <span class="token keyword">const</span> restoreActiveInstance <span class="token operator">=</span> <span class="token function">setActiveInstance</span><span class="token punctuation">(</span>vm<span class="token punctuation">)</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span>prevVnode<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token comment">// initial render</span>
      vm<span class="token punctuation">.</span>$el <span class="token operator">=</span> vm<span class="token punctuation">.</span><span class="token function">__patch__</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$el<span class="token punctuation">,</span> vnode<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span>
    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
      <span class="token comment">// updates</span>
      vm<span class="token punctuation">.</span>$el <span class="token operator">=</span> vm<span class="token punctuation">.</span><span class="token function">__patch__</span><span class="token punctuation">(</span>prevVnode<span class="token punctuation">,</span> vnode<span class="token punctuation">)</span>
    <span class="token punctuation">}</span>
    <span class="token function">restoreActiveInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>这段代码中有几个关键点：</p><ul><li><p><code>vm._vnode = vnode</code></p><p>其中 vnode 是 <code>vm._render</code> 返回的组件渲染 vnode，<code>vm._vnode</code> 和 <code>vm.$vnode</code> 的关系是父子关系，即 <code>vm._vnode.parent === vm.$vnode</code>。</p></li><li><p><code>setActiveInstance</code> 和 <code>restoreActiveInstance</code></p><p>vue 整个初始化是一个深度遍历的过程，实例化组件过程中，需要知道当前上下文的 vue 实例是什么，并把它作为该组件的 parent，即 <code>vm.$parent</code>。</p><p>当前组件 patch 完成时，需要恢复上下文环境。</p></li></ul><h3 id="patch-渲染-vnode" tabindex="-1"><a class="header-anchor" href="#patch-渲染-vnode" aria-hidden="true">#</a> patch 渲染 vnode</h3><p>这里再次走到了 <code>vm.__patch__</code> 函数，和 patch 组件 VNode 不同，这里 patch 的是渲染 vnode，即 App 组件内部的节点 <code>&lt;div id=&quot;app&quot;&gt;...&lt;/div&gt;</code>。 <code>vm.__patch__</code> 函数最终会调用 <code>createElm</code>。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/patch</span>
<span class="token keyword">function</span> <span class="token function">createElm</span><span class="token punctuation">(</span><span class="token parameter">vnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">,</span> parentElm<span class="token punctuation">,</span> <span class="token operator">...</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 对于组件 vnode，比如 helloworld</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">createComponent</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">,</span> parentElm<span class="token punctuation">,</span> refElm<span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span>
  <span class="token punctuation">}</span>

  <span class="token comment">// 对于普通 vnode，比如 &lt;div id=&quot;app&quot;&gt;</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>isTag<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// ...</span>
    vnode<span class="token punctuation">.</span>elm <span class="token operator">=</span> nodeOps<span class="token punctuation">.</span><span class="token function">createElement</span><span class="token punctuation">(</span>tag<span class="token punctuation">,</span> vnode<span class="token punctuation">)</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token keyword">if</span> <span class="token punctuation">(</span>isComment<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    vnode<span class="token punctuation">.</span>elm <span class="token operator">=</span> nodeOps<span class="token punctuation">.</span><span class="token function">createComment</span><span class="token punctuation">(</span>vnode<span class="token punctuation">.</span>text<span class="token punctuation">)</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    vnode<span class="token punctuation">.</span>elm <span class="token operator">=</span> nodeOps<span class="token punctuation">.</span><span class="token function">createTextNode</span><span class="token punctuation">(</span>vnode<span class="token punctuation">.</span>text<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
  <span class="token function">insert</span><span class="token punctuation">(</span>parentElm<span class="token punctuation">,</span> vnode<span class="token punctuation">.</span>elm<span class="token punctuation">,</span> refElm<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><p>对 createElm 函数传入的 vnode 是组件的渲染 vnode，即 vm._vnode。</p><ul><li>如果组件的根节点是普通元素，那么 vm._vnode 也是普通 vnode，则 createComponent 的返回值就是 false</li><li>如果根节点是另一个组件 B，则和之前的内容一样，先创建一个组件占位符，然后接着 render、patch 等一系列操作，直到组件 B 渲染完成</li></ul><h2 id="一个例子" tabindex="-1"><a class="header-anchor" href="#一个例子" aria-hidden="true">#</a> 一个例子</h2><p>以下面这段代码为例，一步步来介绍 new vue 和创建组件的流程：</p><p>App.vue:</p><div class="language-vue" data-ext="vue"><pre class="language-vue"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>app<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>hello-world</span><span class="token punctuation">/&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>

<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;App&#39;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">components</span><span class="token operator">:</span> <span class="token punctuation">{</span> HelloWorld <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>HelloWorld.vue:</p><div class="language-vue" data-ext="vue"><pre class="language-vue"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>hello<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;HelloWorld&#39;</span>
<span class="token punctuation">}</span>
</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p>main.js:</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// main.js</span>
<span class="token keyword">new</span> <span class="token class-name">Vue</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token literal-property property">el</span><span class="token operator">:</span> <span class="token string">&#39;#container&#39;</span><span class="token punctuation">,</span>
  <span class="token function-variable function">render</span><span class="token operator">:</span> <span class="token parameter">h</span> <span class="token operator">=&gt;</span> <span class="token function">h</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span>
</code></pre></div><h3 id="new-vue" tabindex="-1"><a class="header-anchor" href="#new-vue" aria-hidden="true">#</a> new Vue</h3><ul><li><p><code>new Vue</code> 会执行 <code>_init</code> 函数初始化 vue，如果传入了 el，则会调用 <code>$mount</code> 函数。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/instance/init</span>
<span class="token class-name">Vue</span><span class="token punctuation">.</span>prototype<span class="token punctuation">.</span><span class="token function-variable function">_init</span> <span class="token operator">=</span> <span class="token keyword">function</span> <span class="token punctuation">(</span><span class="token parameter">options</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// init ...</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>el<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    vm<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span>vm<span class="token punctuation">.</span>$options<span class="token punctuation">.</span>el<span class="token punctuation">)</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre></div><p>当然也可以手动调用：</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">new</span> <span class="token class-name">Vue</span><span class="token punctuation">(</span><span class="token punctuation">{</span>
  <span class="token function-variable function">render</span><span class="token operator">:</span> <span class="token parameter">h</span> <span class="token operator">=&gt;</span> <span class="token function">h</span><span class="token punctuation">(</span>App<span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span><span class="token string">&#39;#container&#39;</span><span class="token punctuation">)</span>
</code></pre></div></li><li><p><code>$mount</code> 会调用 mountComponent，里面有两个重要方法： <code>vm._update </code>和 <code>vm._render：</code></p><ul><li><code>vm._render</code> 会执行 render 函数，即调用 <code>h(App)</code> 或者说 <code>$createElement(App)</code></li><li><code>vm._update</code> 则会 patch render 函数返回的 vnode</li></ul></li></ul><p>到目前为止还是上章“创建 vue 实例”的内容。</p><p>从 <code>$createElement(App)</code> 开始总结组件化的过程。</p><h3 id="createelement-app" tabindex="-1"><a class="header-anchor" href="#createelement-app" aria-hidden="true">#</a> $createElement(App)</h3><ol><li><p>调用 <code>$createElement &gt;&gt; _createElement &gt;&gt; createComponent</code> 函数创建组件 vnode</p><p>组件 vnode 只是个占位符，tag 名称通常为 <code>vue-component-{cid}-{name}</code>。</p><p>createComponent 主要干了三件事：</p><ul><li><p><code>vue.extend</code> 拓展组件对象，使其具备 vue 的能力</p></li><li><p>安装组件 hook 函数，主要有 init、prepatch、insert、destory 四个 hook 函数</p></li><li><p>创建组件 vnode，这就是 createComponent 的返回值</p></li></ul></li></ol><ul><li>此时 render 完成，调用 <code>update &gt;&gt; patch</code>，也就是说接下来要 patch 组件 vnode</li></ul><h3 id="patch-app-组件-vnode" tabindex="-1"><a class="header-anchor" href="#patch-app-组件-vnode" aria-hidden="true">#</a> patch App 组件 vnode</h3><ul><li><p>执行 <code>patch &gt;&gt; createElm &gt;&gt; createComponent。</code><strong>注意两个 createComponent 函数是不同的：</strong></p><ul><li><p><code>$createElement &gt;&gt; createComponent</code> 位置在<code>core/vdom/create-component</code>，它的作用是创建组件 vnode 占位符。</p></li><li><p><code>patch &gt;&gt; createComponent</code> 位置在 <code>core/vdom/patch</code>，它的作用是 patch 组件</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/patch</span>
<span class="token keyword">function</span> <span class="token function">createElm</span><span class="token punctuation">(</span><span class="token parameter">vnode</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 尝试以组件 vnode 方式创建元素</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token function">createComponent</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> insertedVnodeQueue<span class="token punctuation">,</span> parentElm<span class="token punctuation">,</span> <span class="token operator">...</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token keyword">return</span>
  <span class="token punctuation">}</span>
  <span class="token comment">// 普通 vnode 创建元素流程</span>
<span class="token punctuation">}</span>
</code></pre></div></li></ul></li><li><p>在 <code>patch &gt;&gt; createComponent</code> 中，会执行之前 installComponentHooks 中挂载的 init hook 函数，这会调用 createComponentInstanceForVnode 函数创建一个新的 vue 实例。</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// core/vdom/patch</span>
<span class="token keyword">function</span> <span class="token function">createComponent</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// 调用 init hook</span>
<span class="token punctuation">}</span>
</code></pre></div><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">export</span> <span class="token keyword">function</span> <span class="token function">createComponentInstanceForVnode</span> <span class="token punctuation">(</span><span class="token parameter">vnode<span class="token punctuation">,</span> parent</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token comment">// ...</span>
  <span class="token comment">// 这里类似 new Vue(...)</span>
  <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">vnode<span class="token punctuation">.</span>componentOptions<span class="token punctuation">.</span>Ctor</span><span class="token punctuation">(</span>options<span class="token punctuation">)</span>
<span class="token punctuation">}</span>
</code></pre></div><p><strong>由此可见，每创建一个组件前，都会先继承并创建一个 vue 实例。</strong></p></li></ul><h3 id="mount-app" tabindex="-1"><a class="header-anchor" href="#mount-app" aria-hidden="true">#</a> $mount App</h3><ul><li><p><code>$mount</code> 函数的调用位置是在 createComponentInstanceForVnode 之后</p><div class="language-javascript" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> child <span class="token operator">=</span> <span class="token function">createComponentInstanceForVnode</span><span class="token punctuation">(</span>vnode<span class="token punctuation">,</span> activeInstance<span class="token punctuation">)</span>
child<span class="token punctuation">.</span><span class="token function">$mount</span><span class="token punctuation">(</span><span class="token keyword">undefined</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span>
</code></pre></div></li><li><p><code>$mount</code> 一个组件 vnode，也会调用 <code>$mount &gt;&gt; mountComponent &gt;&gt; vm._render</code>，这会将 App 的 render 函数转成渲染 vnode</p><div class="language-vue" data-ext="vue"><pre class="language-vue"><code>// App.vue
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>template</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span> <span class="token attr-name">class</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>app<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>hello-world</span><span class="token punctuation">/&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>template</span><span class="token punctuation">&gt;</span></span>
</code></pre></div><p><strong>即这段代码对应的 render 函数渲染成 vnode，称为渲染 vnode，不再是占位符。</strong></p><p>然后继续 patch 这些 vnode：</p><ul><li><code>&lt;div class=&quot;app&quot;&gt;</code> 是普通 vnode，直接调用 <code>nodeOps.createElement</code> 创建 dom 节点。</li><li>遇到 <code>&lt;hello-world/&gt;</code> 时，又会再走一遍类似 h(App) 的过程，形成递归关系。</li></ul></li></ul><h2 id="总结" tabindex="-1"><a class="header-anchor" href="#总结" aria-hidden="true">#</a> 总结</h2><p>构建一个组件有以下几步：</p><ul><li>继承 vue、安装 hook 函数、创建占位符 vnode</li><li>patch 占位符 vnode <ul><li>创建一个新的 vue 实例</li><li><code>$mount </code>占位符 vnode <ul><li>调用 render 函数，得到渲染 vnode</li><li>patch 渲染 vnode <ul><li>如果是普通 vnode，比如 div，则直接创建元素</li><li>如果是一个内部组件，重复整个流程</li></ul></li></ul></li></ul></li></ul><p>这是一个递归的过程，组件的构建顺序是<strong>先子后父</strong>。</p><p>需要注意有两点：</p><ul><li>每次遇到组件，都会先创建一个占位符，它是一个 vnode，可以称为组件 vnode。</li><li>在 patch 组件 vnode 前，都会创建一个新的 vue 实例，每个组件对应一个 vue 实例，并和父子组件一样形成树关系。</li></ul><h3 id="组件构建过程" tabindex="-1"><a class="header-anchor" href="#组件构建过程" aria-hidden="true">#</a> 组件构建过程</h3><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1gyjdkgmmemj30qz09hwez.jpg" style="zoom:80%;"><h3 id="vue-实例、组件的树状关系" tabindex="-1"><a class="header-anchor" href="#vue-实例、组件的树状关系" aria-hidden="true">#</a> vue 实例、组件的树状关系</h3><p><img src="https://raw.githubusercontent.com/yamsfeer/pic-bed/master/008i3skNgy1gyj1555zp7j30i30a1mxh.jpg" alt=""></p>`,107),e=[o];function c(l,u){return a(),s("div",null,e)}const r=n(p,[["render",c],["__file","3.组件化.html.vue"]]);export{r as default};
